use std::collections::HashMap;

struct ConfigProcessor {
    rules: HashMap<String, String>,
}

impl ConfigProcessor {
    fn new() -> Self {
        let mut rules = HashMap::new();
        rules.insert("owner".to_string(), "devops@example.com".to_string());
        rules.insert("region".to_string(), "us-west-2".to_string());
        ConfigProcessor { rules }
    }

    fn generate_artifact(&self, resource_name: &str, tags: &[(&str, &str)]) -> String {
        let mut output = format!("Resource: {}
Type: Service
Status: Active
", resource_name);
        output.push_str(&format!("Owner: {}
", self.rules.get("owner").unwrap()));
        output.push_str(&format!("Region: {}
", self.rules.get("region").unwrap()));

        for &(key, value) in tags { 
            output.push_str(&format!("Tag:: {} = {}
", key, value));
        }
        output
    }
}

